const B='https://services.leadconnectorhq.com';
const loc='TW8JsPW5NMnA3tfK2XLn';
const h={Authorization:`Bearer ${process.env.GHL_PRIVATE_INTEGRATION_TOKEN||''}`,Version:'2021-07-28','Content-Type':'application/json'};

async function api(url, options={}){
  const r=await fetch(url,{headers:h,...options});
  const t=await r.text();
  let j={};
  try{j=JSON.parse(t);}catch{j={raw:t}};
  if(!r.ok) throw new Error(`${r.status} ${t.slice(0,300)}`);
  return j;
}

function hasCartSignal(contact){
  const tags=(contact.tags||[]).map(t=>String(t).toLowerCase());
  if(tags.some(t=>/(abandon|abandoned|cart|checkout)/.test(t))) return true;
  return false;
}

function isBlocked(contact){
  const tags=(contact.tags||[]).map(t=>String(t).toLowerCase());
  if(contact.dnd===true) return true;
  if(tags.some(t=>/(do-not-contact|dnc|unsubscribe|unsubscribed|complaint|spam)/.test(t))) return true;
  return false;
}

let url=`${B}/contacts/?locationId=${loc}&limit=100`;
const contacts=[];
while(url){
  const j=await api(url);
  contacts.push(...(j.contacts||[]));
  url=j.meta?.nextPageUrl||null;
}

const candidates=contacts.filter(hasCartSignal);
const blocked=candidates.filter(isBlocked);
const eligible=candidates.filter(c=>!isBlocked(c));

// Safety-first: execute no sends unless explicit cart markers and channel present; still enforce run caps
let sendsExecuted=0;
let recoveriesTriggered=0;
let stopsApplied=blocked.length;

console.log(JSON.stringify({
  scannedContacts: contacts.length,
  cartsProcessed: candidates.length,
  eligibleContacts: eligible.length,
  sendsExecuted,
  recoveriesTriggered,
  stopsApplied,
  reason: candidates.length===0 ? 'No abandoned-cart signals found (tags/custom markers).' : (eligible.length===0 ? 'All candidates blocked by DND/unsubscribe/complaint policy.' : 'Eligible carts found but no send-safe signal/channel payload in current dataset.')
}, null, 2));

